bool cooling_profile_step(float*targets,unsigned long*holds,int n,int*zone,unsigned long*zs,float pv,float tol){
  if(*zone>=n) return true;
  float sp=targets[*zone];
  bool atSP=fabs(pv-sp)<=tol;
  if(atSP && millis()-*zs>holds[*zone]){
    (*zone)++; *zs=millis();
  } else if(!atSP){
    *zs=millis();
  }
  return (*zone>=n);
}
